export function getUnicodeVerticalOrientation(codePoint: number): UnicodeVerticalOrientation {
  let low = 0
  let high = RANGES.length / 3 - 1
  while (low <= high) {
    const middle = (low + high) >> 1
    const offset = middle * 3
    const start = RANGES[offset]!
    const end = RANGES[offset + 1]!
    if (codePoint < start) high = middle - 1
    else if (codePoint > end) low = middle + 1
    else {
      const value = RANGES[offset + 2]!
      return value === 1 ? 'U' : value === 2 ? 'Tu' : 'Tr'
    }
  }
  return 'R'
}
